CREATE TABLE "audit_policy_rules" (
  "id" bigint GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "name" character varying NOT NULL,
  "description" character varying NOT NULL DEFAULT '',
  "source" character varying NOT NULL DEFAULT '',
  "enabled" boolean NOT NULL DEFAULT true,
  "priority" integer NOT NULL DEFAULT 100,
  "effect" character varying NOT NULL,
  "match_type" character varying NOT NULL DEFAULT 'exact',
  "method" character varying NOT NULL DEFAULT '',
  "path_pattern" character varying NOT NULL DEFAULT '',
  "event_type" character varying NOT NULL DEFAULT '',
  "risk_level" character varying NOT NULL DEFAULT '',
  "target_type" character varying NOT NULL DEFAULT '',
  "condition_expr" text NOT NULL DEFAULT '',
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  "updated_at" timestamptz NOT NULL DEFAULT NOW(),
  PRIMARY KEY ("id")
);

CREATE INDEX "audit_policy_rules_priority" ON "audit_policy_rules" ("priority", "id");
CREATE INDEX "audit_policy_rules_source" ON "audit_policy_rules" ("source");
CREATE INDEX "audit_policy_rules_event_type" ON "audit_policy_rules" ("event_type");
CREATE INDEX "audit_policy_rules_path_pattern" ON "audit_policy_rules" ("path_pattern");
CREATE UNIQUE INDEX "audit_policy_rules_name" ON "audit_policy_rules" ("name");

